// Combine all MCQs
export const allFinalSuggestionMCQs: MCQ[] = [
  ...finalSuggestionMCQs, 
  ...additionalMCQsBatch2, 
  ...additionalMCQsBatch3,
  ...additionalMCQsBatch4
];

// Export helper functions
export const getMCQsByTopic = (topic: string, mcqs: MCQ[] = allFinalSuggestionMCQs) => {
  return mcqs.filter(mcq => mcq.topic === topic);
};

export const getTopics = (mcqs: MCQ[] = allFinalSuggestionMCQs) => {
  return [...new Set(mcqs.map(mcq => mcq.topic))];
};

export const getShuffledMCQs = (mcqs: MCQ[] = allFinalSuggestionMCQs) => {
  return shuffleArray(mcqs);
};

export const getRandomizedOptions = (mcq: MCQ): { options: string[]; correctIndex: number } => {
  const optionsWithIndex = mcq.options.map((opt, idx) => ({ text: opt, isCorrect: idx === mcq.correctAnswer }));
  const shuffled = shuffleArray(optionsWithIndex);
  return {
    options: shuffled.map(o => o.text),
    correctIndex: shuffled.findIndex(o => o.isCorrect)
  };
};
